code.perFrame:
zoom = 0.9999;
rot = 0;
dx = 0;
dy = 0;
sx = 0.9999;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
dec_med = 1- .2*30/fps;;
dec_slow = 1-.05*30/fps;;
beat = max (max (bass, mid), treb);;
avg = avg*dec_slow + beat*(1-dec_slow);;
is_beat = ((beat) > (1.2*avg+peak)) * ((time) > (t0+.2));;
t0 = is_beat*time + (1-is_beat)*t0;;
peak = is_beat * beat + (1-is_beat)*peak*dec_med;;
index = (index + is_beat) %16;;
q27 = index;;
peak_ = dec_med*peak_ + (1-dec_med)*peak;;
ma = ma + (peak_-1)*(index%2)/fps*10;;
mx=mx*dec_slow+(1-dec_slow)*cos(ma);;
my=my*dec_slow+(1-dec_slow)*sin(ma);;
q15 = mx/2 ;;
q16 = my/2 ;;
q17 = ma;;
q32 = aspectx;;
monitor = q27;
